unit lipdecide;

{$mode objfpc}

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses
  Math;

const
  LIC_COUNT = 15;

function ScaleFactorSixDigits(const Value: real): integer;
var
  logValue: real;
begin
  if Value <= 0.0 then
    Exit(0);
  logValue := Log10(Value);
  Result := Trunc(Floor(logValue));
end;

function REALCOMPARE(A, B: real): COMPTYPE;
const
  SIGNIFICANT_DIGITS = 6;
var
  maxAbs, scale, diff: real;
  order: integer;
  scaledA, scaledB: Int64;
begin
  diff := A - B;
  if diff = 0.0 then
    Exit(EQ);

  maxAbs := Abs(A);
  if Abs(B) > maxAbs then
    maxAbs := Abs(B);

  if maxAbs = 0.0 then
    maxAbs := 1.0;

  order := ScaleFactorSixDigits(maxAbs);
  scale := Power(10.0, order - (SIGNIFICANT_DIGITS - 1));

  if scale = 0.0 then
    scale := 1.0;

  scaledA := Round(A / scale);
  scaledB := Round(B / scale);

  if scaledA = scaledB then
    Exit(EQ)
  else if scaledA < scaledB then
    Exit(LT)
  else
    Exit(GT);
end;

function DistanceBetweenPoints(i, j: integer): real;
var
  dx, dy: real;
begin
  dx := X[j] - X[i];
  dy := Y[j] - Y[i];
  Result := Sqrt(dx * dx + dy * dy);
end;

function TriangleArea(i, j, k: integer): real;
var
  area: real;
begin
  area := ((X[j] - X[i]) * (Y[k] - Y[i])) - ((Y[j] - Y[i]) * (X[k] - X[i]));
  Result := Abs(area) * 0.5;
end;

function PointsEqual(i, j: integer): boolean;
begin
  Result := (REALCOMPARE(X[i], X[j]) = EQ) and (REALCOMPARE(Y[i], Y[j]) = EQ);
end;

function FitsCircle(i, j, k: integer; radius: real): boolean;
var
  a, b, c, maxDist, twiceRadius, area, denom, circumRadius: real;
begin
  if REALCOMPARE(radius, 0.0) = LT then
    Exit(false);

  a := DistanceBetweenPoints(i, j);
  b := DistanceBetweenPoints(j, k);
  c := DistanceBetweenPoints(i, k);

  maxDist := a;
  if REALCOMPARE(b, maxDist) = GT then
    maxDist := b;
  if REALCOMPARE(c, maxDist) = GT then
    maxDist := c;

  twiceRadius := radius * 2.0;
  if REALCOMPARE(maxDist, twiceRadius) = GT then
    Exit(false);

  area := TriangleArea(i, j, k);
  if REALCOMPARE(area, 0.0) = EQ then
    Exit(true);

  denom := 4.0 * area;
  if REALCOMPARE(denom, 0.0) = EQ then
    Exit(false);

  circumRadius := (a * b * c) / denom;
  Result := REALCOMPARE(circumRadius, radius) <> GT;
end;

function AngleExceedsTolerance(i, j, k: integer; epsilon: real): boolean;
var
  ux, uy, vx, vy, magU, magV, dotProd, cosTheta, angle, piMinus, piPlus: real;
begin
  ux := X[i] - X[j];
  uy := Y[i] - Y[j];
  vx := X[k] - X[j];
  vy := Y[k] - Y[j];

  magU := Sqrt(ux * ux + uy * uy);
  magV := Sqrt(vx * vx + vy * vy);

  if (REALCOMPARE(magU, 0.0) = EQ) or (REALCOMPARE(magV, 0.0) = EQ) then
    Exit(false);

  dotProd := (ux * vx) + (uy * vy);
  cosTheta := dotProd / (magU * magV);
  if cosTheta < -1.0 then
    cosTheta := -1.0
  else if cosTheta > 1.0 then
    cosTheta := 1.0;

  angle := ArcCos(cosTheta);
  piMinus := PI - epsilon;
  piPlus := PI + epsilon;

  if REALCOMPARE(angle, piMinus) = LT then
    Exit(true)
  else if REALCOMPARE(angle, piPlus) = GT then
    Exit(true)
  else
    Exit(false);
end;

function DistancePointToLine(x1, y1, x2, y2, x0, y0: real): real;
var
  dx, dy, lineLen: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  lineLen := Sqrt(dx * dx + dy * dy);
  if REALCOMPARE(lineLen, 0.0) = EQ then
  begin
    Result := Sqrt(Sqr(x0 - x1) + Sqr(y0 - y1));
    Exit;
  end;
  Result := Abs(((x0 - x1) * dy) - ((y0 - y1) * dx)) / lineLen;
end;

function DetermineQuadrant(idx: integer): integer;
var
  xVal, yVal: real;
begin
  xVal := X[idx];
  yVal := Y[idx];
  if (REALCOMPARE(xVal, 0.0) <> LT) and (REALCOMPARE(yVal, 0.0) <> LT) then
    Exit(1)
  else if (REALCOMPARE(xVal, 0.0) = LT) and (REALCOMPARE(yVal, 0.0) <> LT) then
    Exit(2)
  else if (REALCOMPARE(yVal, 0.0) = LT) and (REALCOMPARE(xVal, 0.0) <> GT) then
    Exit(3)
  else
    Exit(4);
end;

function LIC1: boolean;
var
  i: integer;
  dist: real;
begin
  Result := false;
  if NUMPOINTS < 2 then
    Exit(false);
  for i := 1 to NUMPOINTS - 1 do
  begin
    dist := DistanceBetweenPoints(i, i + 1);
    if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
    begin
      Result := true;
      Exit;
    end;
  end;
end;

function LIC2: boolean;
var
  i: integer;
begin
  if NUMPOINTS < 3 then
    Exit(false);
  if REALCOMPARE(PARAMETERS.RADIUS1, 0.0) = LT then
    Exit(false);
  for i := 1 to NUMPOINTS - 2 do
    if not FitsCircle(i, i + 1, i + 2, PARAMETERS.RADIUS1) then
      Exit(true);
  Result := false;
end;

function LIC3: boolean;
var
  i: integer;
begin
  if NUMPOINTS < 3 then
    Exit(false);
  for i := 1 to NUMPOINTS - 2 do
    if AngleExceedsTolerance(i, i + 1, i + 2, PARAMETERS.EPSILON) then
      Exit(true);
  Result := false;
end;

function LIC4: boolean;
var
  i: integer;
  area: real;
begin
  if NUMPOINTS < 3 then
    Exit(false);
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := TriangleArea(i, i + 1, i + 2);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      Exit(true);
  end;
  Result := false;
end;

function LIC5: boolean;
var
  qPts, quads, startIdx, idx, usedCount, quadrant: integer;
  used: array[1..4] of boolean;
begin
  qPts := PARAMETERS.Q_PTS;
  quads := PARAMETERS.QUADS;
  if (qPts < 2) or (qPts > NUMPOINTS) then
    Exit(false);
  if (quads < 1) or (quads > 3) then
    Exit(false);
  for startIdx := 1 to NUMPOINTS - qPts + 1 do
  begin
    FillChar(used, SizeOf(used), 0);
    usedCount := 0;
    for idx := startIdx to startIdx + qPts - 1 do
    begin
      quadrant := DetermineQuadrant(idx);
      if not used[quadrant] then
      begin
        used[quadrant] := true;
        Inc(usedCount);
      end;
    end;
    if usedCount > quads then
      Exit(true);
  end;
  Result := false;
end;

function LIC6: boolean;
var
  i: integer;
begin
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[i + 1], X[i]) = LT then
      Exit(true);
  Result := false;
end;

function LIC7: boolean;
var
  nPts, startIdx, endIdx, idx: integer;
  dist, lineDist: real;
  sameEndpoint: boolean;
begin
  nPts := PARAMETERS.N_PTS;
  if (NUMPOINTS < 3) or (nPts < 3) or (nPts > NUMPOINTS) then
    Exit(false);
  for startIdx := 1 to NUMPOINTS - nPts + 1 do
  begin
    endIdx := startIdx + nPts - 1;
    sameEndpoint := PointsEqual(startIdx, endIdx);
    for idx := startIdx to endIdx do
    begin
      if sameEndpoint then
        lineDist := DistanceBetweenPoints(startIdx, idx)
      else
        lineDist := DistancePointToLine(X[startIdx], Y[startIdx], X[endIdx], Y[endIdx], X[idx], Y[idx]);
      if REALCOMPARE(lineDist, PARAMETERS.DIST) = GT then
        Exit(true);
    end;
  end;
  Result := false;
end;

function LIC8: boolean;
var
  kPts, i, j: integer;
  dist: real;
begin
  if NUMPOINTS < 3 then
    Exit(false);
  kPts := PARAMETERS.K_PTS;
  if (kPts < 1) or (kPts > NUMPOINTS - 2) then
    Exit(false);
  for i := 1 to NUMPOINTS - kPts - 1 do
  begin
    j := i + kPts + 1;
    dist := DistanceBetweenPoints(i, j);
    if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
      Exit(true);
  end;
  Result := false;
end;

function LIC9: boolean;
var
  aPts, bPts, startIdx, j, k, limit: integer;
begin
  if NUMPOINTS < 5 then
    Exit(false);
  if REALCOMPARE(PARAMETERS.RADIUS1, 0.0) = LT then
    Exit(false);
  aPts := PARAMETERS.A_PTS;
  bPts := PARAMETERS.B_PTS;
  if (aPts < 1) or (bPts < 1) or (aPts + bPts > NUMPOINTS - 3) then
    Exit(false);
  limit := NUMPOINTS - (aPts + bPts + 2);
  for startIdx := 1 to limit do
  begin
    j := startIdx + aPts + 1;
    k := j + bPts + 1;
    if not FitsCircle(startIdx, j, k, PARAMETERS.RADIUS1) then
      Exit(true);
  end;
  Result := false;
end;

function LIC10: boolean;
var
  cPts, dPts, startIdx, j, k, limit: integer;
begin
  if NUMPOINTS < 5 then
    Exit(false);
  cPts := PARAMETERS.C_PTS;
  dPts := PARAMETERS.D_PTS;
  if (cPts < 1) or (dPts < 1) or (cPts + dPts > NUMPOINTS - 3) then
    Exit(false);
  limit := NUMPOINTS - (cPts + dPts + 2);
  for startIdx := 1 to limit do
  begin
    j := startIdx + cPts + 1;
    k := j + dPts + 1;
    if AngleExceedsTolerance(startIdx, j, k, PARAMETERS.EPSILON) then
      Exit(true);
  end;
  Result := false;
end;

function LIC11: boolean;
var
  ePts, fPts, startIdx, j, k, limit: integer;
  area: real;
begin
  if NUMPOINTS < 5 then
    Exit(false);
  ePts := PARAMETERS.E_PTS;
  fPts := PARAMETERS.F_PTS;
  if (ePts < 1) or (fPts < 1) or (ePts + fPts > NUMPOINTS - 3) then
    Exit(false);
  limit := NUMPOINTS - (ePts + fPts + 2);
  for startIdx := 1 to limit do
  begin
    j := startIdx + ePts + 1;
    k := j + fPts + 1;
    area := TriangleArea(startIdx, j, k);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      Exit(true);
  end;
  Result := false;
end;

function LIC12: boolean;
var
  gPts, i, j: integer;
begin
  if NUMPOINTS < 3 then
    Exit(false);
  gPts := PARAMETERS.G_PTS;
  if (gPts < 1) or (gPts > NUMPOINTS - 2) then
    Exit(false);
  for i := 1 to NUMPOINTS - gPts - 1 do
  begin
    j := i + gPts + 1;
    if REALCOMPARE(X[j], X[i]) = LT then
      Exit(true);
  end;
  Result := false;
end;

function LIC13: boolean;
var
  kPts, i, j: integer;
  dist: real;
  foundLong, foundShort: boolean;
begin
  if NUMPOINTS < 3 then
    Exit(false);
  kPts := PARAMETERS.K_PTS;
  if (kPts < 1) or (kPts > NUMPOINTS - 2) then
    Exit(false);
  if REALCOMPARE(PARAMETERS.LENGTH2, 0.0) = LT then
    Exit(false);
  foundLong := false;
  foundShort := false;
  for i := 1 to NUMPOINTS - kPts - 1 do
  begin
    j := i + kPts + 1;
    dist := DistanceBetweenPoints(i, j);
    if not foundLong and (REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT) then
      foundLong := true;
    if not foundShort and (REALCOMPARE(dist, PARAMETERS.LENGTH2) = LT) then
      foundShort := true;
    if foundLong and foundShort then
      Exit(true);
  end;
  Result := false;
end;

function LIC14: boolean;
var
  aPts, bPts, startIdx, j, k, limit: integer;
  foundLarge, foundSmall: boolean;
begin
  if NUMPOINTS < 5 then
    Exit(false);
  if (REALCOMPARE(PARAMETERS.RADIUS1, 0.0) = LT) or (REALCOMPARE(PARAMETERS.RADIUS2, 0.0) = LT) then
    Exit(false);
  aPts := PARAMETERS.A_PTS;
  bPts := PARAMETERS.B_PTS;
  if (aPts < 1) or (bPts < 1) or (aPts + bPts > NUMPOINTS - 3) then
    Exit(false);
  limit := NUMPOINTS - (aPts + bPts + 2);
  foundLarge := false;
  foundSmall := false;
  for startIdx := 1 to limit do
  begin
    j := startIdx + aPts + 1;
    k := j + bPts + 1;
    if not FitsCircle(startIdx, j, k, PARAMETERS.RADIUS1) then
      foundLarge := true;
    if FitsCircle(startIdx, j, k, PARAMETERS.RADIUS2) then
      foundSmall := true;
    if foundLarge and foundSmall then
      Exit(true);
  end;
  Result := false;
end;

function LIC15: boolean;
var
  ePts, fPts, startIdx, j, k, limit: integer;
  area: real;
  foundLarge, foundSmall: boolean;
begin
  if NUMPOINTS < 5 then
    Exit(false);
  if REALCOMPARE(PARAMETERS.AREA2, 0.0) = LT then
    Exit(false);
  ePts := PARAMETERS.E_PTS;
  fPts := PARAMETERS.F_PTS;
  if (ePts < 1) or (fPts < 1) or (ePts + fPts > NUMPOINTS - 3) then
    Exit(false);
  limit := NUMPOINTS - (ePts + fPts + 2);
  foundLarge := false;
  foundSmall := false;
  for startIdx := 1 to limit do
  begin
    j := startIdx + ePts + 1;
    k := j + fPts + 1;
    area := TriangleArea(startIdx, j, k);
    if not foundLarge and (REALCOMPARE(area, PARAMETERS.AREA1) = GT) then
      foundLarge := true;
    if not foundSmall and (REALCOMPARE(area, PARAMETERS.AREA2) = LT) then
      foundSmall := true;
    if foundLarge and foundSmall then
      Exit(true);
  end;
  Result := false;
end;

procedure BuildCMV;
begin
  CMV[1]  := LIC1;
  CMV[2]  := LIC2;
  CMV[3]  := LIC3;
  CMV[4]  := LIC4;
  CMV[5]  := LIC5;
  CMV[6]  := LIC6;
  CMV[7]  := LIC7;
  CMV[8]  := LIC8;
  CMV[9]  := LIC9;
  CMV[10] := LIC10;
  CMV[11] := LIC11;
  CMV[12] := LIC12;
  CMV[13] := LIC13;
  CMV[14] := LIC14;
  CMV[15] := LIC15;
end;

procedure BuildPUM;
var
  i, j: integer;
begin
  for i := 1 to LIC_COUNT do
    for j := 1 to LIC_COUNT do
      if i <> j then
      begin
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ORR:     PUM[i, j] := CMV[i] or CMV[j];
          ANDD:    PUM[i, j] := CMV[i] and CMV[j];
        end;
      end;
end;

procedure BuildFUV;
var
  i, j: integer;
  rowAllTrue: boolean;
begin
  for i := 1 to LIC_COUNT do
  begin
    if not PUM[i, i] then
    begin
      FUV[i] := true;
      Continue;
    end;
    rowAllTrue := true;
    for j := 1 to LIC_COUNT do
      if not PUM[i, j] then
      begin
        rowAllTrue := false;
        Break;
      end;
    FUV[i] := rowAllTrue;
  end;
end;

procedure ComputeLaunchDecision;
var
  i: integer;
begin
  LAUNCH := true;
  for i := 1 to LIC_COUNT do
    if not FUV[i] then
    begin
      LAUNCH := false;
      Exit;
    end;
end;

procedure DECIDE;
begin
  BuildCMV;
  BuildPUM;
  BuildFUV;
  ComputeLaunchDecision;
end;

end.
